tlScroobyMultiTextChunk::operator==(const tlDataChunk& a)
{

    const tlScroobyMultiTextChunk* aptr = dynamic_cast<const tlScroobyMultiTextChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(version == aptr->version))
    {
        return false;
    }
    if(!(positionx == aptr->positionx))
    {
        return false;
    }
    if(!(positiony == aptr->positiony))
    {
        return false;
    }
    if(!(dimensionx == aptr->dimensionx))
    {
        return false;
    }
    if(!(dimensiony == aptr->dimensiony))
    {
        return false;
    }
    if(!(justificationx == aptr->justificationx))
    {
        return false;
    }
    if(!(justificationy == aptr->justificationy))
    {
        return false;
    }
    if(!(color == aptr->color))
    {
        return false;
    }
    if(!(translucency == aptr->translucency))
    {
        return false;
    }
    if(!(rotationvalue == aptr->rotationvalue))
    {
        return false;
    }
    if(strcmp(textstylename, aptr->textstylename) != 0)
    {
        return false;
    }
    if(!(shadowenabled == aptr->shadowenabled))
    {
        return false;
    }
    if(!(shadowcolour == aptr->shadowcolour))
    {
        return false;
    }
    if(!(shadowoffsetx == aptr->shadowoffsetx))
    {
        return false;
    }
    if(!(shadowoffsety == aptr->shadowoffsety))
    {
        return false;
    }
    if(!(currenttext == aptr->currenttext))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlScroobyMultiTextChunk::NameCompare(const tlDataChunk& a)
{

    const tlScroobyMultiTextChunk* aptr = dynamic_cast<const tlScroobyMultiTextChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }

    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    return true;
}


