void
tlScroobyMultiTextChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutPString(name);
        f->PutLong(version);
        f->PutLong(positionx);
        f->PutLong(positiony);
        f->PutLong(dimensionx);
        f->PutLong(dimensiony);
        f->PutLong(justificationx);
        f->PutLong(justificationy);
        f->PutLong(color);
        f->PutLong(translucency);
        f->PutFloat(rotationvalue);
        f->PutPString(textstylename);
        f->PutChar(shadowenabled);
        f->PutLong(shadowcolour);
        f->PutLong(shadowoffsetx);
        f->PutLong(shadowoffsety);
        f->PutLong(currenttext);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlScroobyMultiTextChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlScroobyMultiTextChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Name           = \"%s\"\n",indent,"",name);
    printf("%*s  Version        = %ld\n",indent,"",version);
    printf("%*s  PositionX      = %ld\n",indent,"",positionx);
    printf("%*s  PositionY      = %ld\n",indent,"",positiony);
    printf("%*s  DimensionX     = %ld\n",indent,"",dimensionx);
    printf("%*s  DimensionY     = %ld\n",indent,"",dimensiony);
    printf("%*s  JustificationX = %ld\n",indent,"",justificationx);
    printf("%*s  JustificationY = %ld\n",indent,"",justificationy);
    printf("%*s  Color          = %08lx\n",indent,"",color);
    printf("%*s  Translucency   = %ld\n",indent,"",translucency);
    printf("%*s  RotationValue  = %f\n",indent,"",rotationvalue);
    printf("%*s  TextStyleName  = \"%s\"\n",indent,"",textstylename);
    printf("%*s  ShadowEnabled  = %d\n",indent,"",shadowenabled);
    printf("%*s  ShadowColour   = %08lx\n",indent,"",shadowcolour);
    printf("%*s  ShadowOffsetX  = %ld\n",indent,"",shadowoffsetx);
    printf("%*s  ShadowOffsetY  = %ld\n",indent,"",shadowoffsety);
    printf("%*s  CurrentText    = %ld\n",indent,"",currenttext);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlScroobyMultiTextChunk::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  pstring \"%s\" # Name          \n",indent,"",name);
    printf("%*s  int   %12ld # Version       \n",indent,"",version);
    printf("%*s  int   %12ld # PositionX     \n",indent,"",positionx);
    printf("%*s  int   %12ld # PositionY     \n",indent,"",positiony);
    printf("%*s  int   %12ld # DimensionX    \n",indent,"",dimensionx);
    printf("%*s  int   %12ld # DimensionY    \n",indent,"",dimensiony);
    printf("%*s  int   %12ld # JustificationX\n",indent,"",justificationx);
    printf("%*s  int   %12ld # JustificationY\n",indent,"",justificationy);
    printf("%*s  int   0x%08lx # Color         \n",indent,"",color);
    printf("%*s  int   %12ld # Translucency  \n",indent,"",translucency);
    printf("%*s  float %12f # RotationValue \n",indent,"",rotationvalue);
    printf("%*s  pstring \"%s\" # TextStyleName \n",indent,"",textstylename);
    printf("%*s  byte  %12d # ShadowEnabled \n",indent,"",shadowenabled);
    printf("%*s  int   0x%08lx # ShadowColour  \n",indent,"",shadowcolour);
    printf("%*s  int   %12ld # ShadowOffsetX \n",indent,"",shadowoffsetx);
    printf("%*s  int   %12ld # ShadowOffsetY \n",indent,"",shadowoffsety);
    printf("%*s  int   %12ld # CurrentText   \n",indent,"",currenttext);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

