tlDataChunk*
tlScroobyMultiTextChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Pure3D::Scrooby::STRINGTEXTBIBLE:
        dch = new tlScroobyStringTextBibleChunk(&ch);
        break;
    case Pure3D::Scrooby::STRINGHARDCODED:
        dch = new tlScroobyStringHardCodedChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

