// tlScroobyPolygonChunk

int tlScroobyPolygonChunk::sortPriority = -1;

tlScroobyPolygonChunk::tlScroobyPolygonChunk()
{
    Init();
}

tlScroobyPolygonChunk::tlScroobyPolygonChunk(const tlScroobyPolygonChunk& ch)
{
    Init();
    *this = ch;
}

tlScroobyPolygonChunk::~tlScroobyPolygonChunk()
{

    if(name != NULL){
        strdelete(name);
    }
    if(points != NULL){
        delete[] points;
    }
    if(colors != NULL){
        delete[] colors;
    }
}

tlScroobyPolygonChunk::tlScroobyPolygonChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Scrooby::POLYGON);
    ident = Pure3D::Scrooby::POLYGON;

    tlFile* f = ch->GetFile();
    unsigned int i;
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    version = f->GetLong();
    translucency = f->GetLong();
    numpoints = f->GetLong();
    points = new tlPoint[numpoints];
    for(i = 0; i < numpoints; i++)
    {
        points[i].Read(f);
    }
    colors = new tlColour[numpoints];
    for(i = 0; i < numpoints; i++)
    {
        colors[i].Read(f);
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Scrooby::POLYGON);
    }
}

void
tlScroobyPolygonChunk::Init()
{
    ident = Pure3D::Scrooby::POLYGON;
    name = NULL;
    version = 0;
    translucency = 0;
    numpoints = 0;
    points = NULL;
    colors = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Scrooby::POLYGON);
    }
}

long 
tlScroobyPolygonChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( name );
    s += sizeof( version );
    s += sizeof( translucency );
    s += sizeof( numpoints );
    for(i = 0; i < (int)numpoints; i++)
    {
        s += sizeof( points[i ] );
    }
    for(i = 0; i < (int)numpoints; i++)
    {
        s += sizeof( colors[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlScroobyPolygonChunk&
tlScroobyPolygonChunk::operator=(const tlScroobyPolygonChunk& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    name = strnew(a.name);
    version = a.version;
    translucency = a.translucency;
    numpoints = a.numpoints;
    if(points)
    {
        delete points;
    }
    points = new tlPoint[numpoints];
    for( i = 0; i < numpoints ; i++ )
    {
        points[i] = a.points[i];
    }
    if(colors)
    {
        delete colors;
    }
    colors = new tlColour[numpoints];
    for( i = 0; i < numpoints ; i++ )
    {
        colors[i] = a.colors[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlScroobyPolygonChunk::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlScroobyPolygonChunk* aptr = dynamic_cast<const tlScroobyPolygonChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(version == aptr->version))
    {
        return false;
    }
    if(!(translucency == aptr->translucency))
    {
        return false;
    }
    if(!(numpoints == aptr->numpoints))
    {
        return false;
    }
    for(i = 0; i < numpoints; i++)
    {
        if(!(points[i] == aptr->points[i]))
        {
            return false;
        }
    }
    for(i = 0; i < numpoints; i++)
    {
        if(!(colors[i] == aptr->colors[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

