int tlScroobyGroupChunk::sortPriority = -1;

tlScroobyGroupChunk::tlScroobyGroupChunk()
{
    Init();
}

tlScroobyGroupChunk::tlScroobyGroupChunk(const tlScroobyGroupChunk& ch)
{
    Init();
    *this = ch;
}

tlScroobyGroupChunk::~tlScroobyGroupChunk()
{

    if(name != NULL){
        strdelete(name);
    }
}

tlScroobyGroupChunk::tlScroobyGroupChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Scrooby::GROUP);
    ident = Pure3D::Scrooby::GROUP;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    version = f->GetLong();
    alpha = f->GetLong();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Scrooby::GROUP);
    }
}

void
tlScroobyGroupChunk::Init()
{
    ident = Pure3D::Scrooby::GROUP;
    name = NULL;
    version = 0;
    alpha = 0;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Scrooby::GROUP);
    }
}

long 
tlScroobyGroupChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( name );
    s += sizeof( version );
    s += sizeof( alpha );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlScroobyGroupChunk&
tlScroobyGroupChunk::operator=(const tlScroobyGroupChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    name = strnew(a.name);
    version = a.version;
    alpha = a.alpha;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlScroobyGroupChunk::operator==(const tlDataChunk& a)
{

    const tlScroobyGroupChunk* aptr = dynamic_cast<const tlScroobyGroupChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(version == aptr->version))
    {
        return false;
    }
    if(!(alpha == aptr->alpha))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

