tlDataChunk*
tlScroobyGroupChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Pure3D::Scrooby::GROUP:
        dch = new tlScroobyGroupChunk(&ch);
        break;
    case Pure3D::Scrooby::MULTISPRITE:
        dch = new tlScroobyMultiSpriteChunk(&ch);
        break;
    case Pure3D::Scrooby::MULTITEXT:
        dch = new tlScroobyMultiTextChunk(&ch);
        break;
    case Pure3D::Scrooby::POLYGON:
        dch = new tlScroobyPolygonChunk(&ch);
        break;
    case Pure3D::Scrooby::P3DOBJECT:
        dch = new tlScroobyPure3dObjectChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

