int tlScroobyTextBibleChunk::sortPriority = -1;

tlScroobyTextBibleChunk::tlScroobyTextBibleChunk()
{
    Init();
}

tlScroobyTextBibleChunk::tlScroobyTextBibleChunk(const tlScroobyTextBibleChunk& ch)
{
    Init();
    *this = ch;
}

tlScroobyTextBibleChunk::~tlScroobyTextBibleChunk()
{

    if(name != NULL){
        strdelete(name);
    }
    if(languages != NULL){
        strdelete(languages);
    }
}

tlScroobyTextBibleChunk::tlScroobyTextBibleChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Scrooby::TEXTBIBLE);
    ident = Pure3D::Scrooby::TEXTBIBLE;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    numlanguages = f->GetLong();
    f->GetPString(buf);
    languages = strnew(buf);
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Scrooby::TEXTBIBLE);
    }
}

void
tlScroobyTextBibleChunk::Init()
{
    ident = Pure3D::Scrooby::TEXTBIBLE;
    name = NULL;
    numlanguages = 0;
    languages = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Scrooby::TEXTBIBLE);
    }
}

long 
tlScroobyTextBibleChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( name );
    s += sizeof( numlanguages );
    s += strlen( languages );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlScroobyTextBibleChunk&
tlScroobyTextBibleChunk::operator=(const tlScroobyTextBibleChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    name = strnew(a.name);
    numlanguages = a.numlanguages;
    languages = strnew(a.languages);

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

