int tlScroobyLanguageChunk::sortPriority = -1;

tlScroobyLanguageChunk::tlScroobyLanguageChunk()
{
    Init();
}

tlScroobyLanguageChunk::tlScroobyLanguageChunk(const tlScroobyLanguageChunk& ch)
{
    Init();
    *this = ch;
}

tlScroobyLanguageChunk::~tlScroobyLanguageChunk()
{

    if(name != NULL){
        strdelete(name);
    }
    if(hashes != NULL){
        delete[] hashes;
    }
    if(offsets != NULL){
        delete[] offsets;
    }
    if(buffer != NULL){
        delete[] buffer;
    }
}

tlScroobyLanguageChunk::tlScroobyLanguageChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Scrooby::LANGUAGE);
    ident = Pure3D::Scrooby::LANGUAGE;

    tlFile* f = ch->GetFile();
    unsigned int i;
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    language = f->GetChar();
    numstrings = f->GetLong();
    modulo = f->GetLong();
    sizeofbuffer = f->GetLong();
    hashes = new unsigned long[numstrings];
    for(i = 0; i < numstrings; i++)
    {
        hashes[i] = f->GetLong();
    }
    offsets = new unsigned long[numstrings];
    for(i = 0; i < numstrings; i++)
    {
        offsets[i] = f->GetLong();
    }
    buffer = new unsigned char[sizeofbuffer];
    for(i = 0; i < sizeofbuffer; i++)
    {
        buffer[i] = f->GetChar();
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Scrooby::LANGUAGE);
    }
}

void
tlScroobyLanguageChunk::Init()
{
    ident = Pure3D::Scrooby::LANGUAGE;
    name = NULL;
    language = 0;
    numstrings = 0;
    modulo = 0;
    sizeofbuffer = 0;
    hashes = NULL;
    offsets = NULL;
    buffer = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Scrooby::LANGUAGE);
    }
}

long 
tlScroobyLanguageChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( name );
    s += sizeof( language );
    s += sizeof( numstrings );
    s += sizeof( modulo );
    s += sizeof( sizeofbuffer );
    for(i = 0; i < (int)numstrings; i++)
    {
        s += sizeof( hashes[i ] );
    }
    for(i = 0; i < (int)numstrings; i++)
    {
        s += sizeof( offsets[i ] );
    }
    for(i = 0; i < (int)sizeofbuffer; i++)
    {
        s += sizeof( buffer[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlScroobyLanguageChunk&
tlScroobyLanguageChunk::operator=(const tlScroobyLanguageChunk& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    name = strnew(a.name);
    language = a.language;
    numstrings = a.numstrings;
    modulo = a.modulo;
    sizeofbuffer = a.sizeofbuffer;
    if(hashes)
    {
        delete hashes;
    }
    hashes = new unsigned long[numstrings];
    for( i = 0; i < numstrings ; i++ )
    {
        hashes[i] = a.hashes[i];
    }
    if(offsets)
    {
        delete offsets;
    }
    offsets = new unsigned long[numstrings];
    for( i = 0; i < numstrings ; i++ )
    {
        offsets[i] = a.offsets[i];
    }
    if(buffer)
    {
        delete buffer;
    }
    buffer = new unsigned char[sizeofbuffer];
    for( i = 0; i < sizeofbuffer ; i++ )
    {
        buffer[i] = a.buffer[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlScroobyLanguageChunk::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlScroobyLanguageChunk* aptr = dynamic_cast<const tlScroobyLanguageChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(language == aptr->language))
    {
        return false;
    }
    if(!(numstrings == aptr->numstrings))
    {
        return false;
    }
    if(!(modulo == aptr->modulo))
    {
        return false;
    }
    if(!(sizeofbuffer == aptr->sizeofbuffer))
    {
        return false;
    }
    for(i = 0; i < numstrings; i++)
    {
        if(!(hashes[i] == aptr->hashes[i]))
        {
            return false;
        }
    }
    for(i = 0; i < numstrings; i++)
    {
        if(!(offsets[i] == aptr->offsets[i]))
        {
            return false;
        }
    }
    for(i = 0; i < sizeofbuffer; i++)
    {
        if(!(buffer[i] == aptr->buffer[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlScroobyLanguageChunk::NameCompare(const tlDataChunk& a)
{

    const tlScroobyLanguageChunk* aptr = dynamic_cast<const tlScroobyLanguageChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }

    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    return true;
}


