void
tlScroobyLanguageChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

    unsigned int i;
        f->PutPString(name);
        f->PutChar(language);
        f->PutLong(numstrings);
        f->PutLong(modulo);
        f->PutLong(sizeofbuffer);
    for(i = 0; i < numstrings ; i++)
    {
        f->PutLong(hashes[i]);
    }
    for(i = 0; i < numstrings ; i++)
    {
        f->PutLong(offsets[i]);
    }
    for(i = 0; i < sizeofbuffer ; i++)
    {
        f->PutChar(buffer[i]);
    }

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlScroobyLanguageChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{
    unsigned int i;

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlScroobyLanguageChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Name         = \"%s\"\n",indent,"",name);
    printf("%*s  Language     = %d\n",indent,"",language);
    printf("%*s  NumStrings   = %ld\n",indent,"",numstrings);
    printf("%*s  Modulo       = %ld\n",indent,"",modulo);
    printf("%*s  SizeOfBuffer = %ld\n",indent,"",sizeofbuffer);
    printf("%*s  Hashes:\n",indent,"");
    for( i=0; i < numstrings; i++)
    {
         printf("%*s    %d %ld\n",indent,"",i,hashes[i]);
    }
    printf("%*s  Offsets:\n",indent,"");
    for( i=0; i < numstrings; i++)
    {
         printf("%*s    %d %ld\n",indent,"",i,offsets[i]);
    }
    printf("%*s  Buffer:\n",indent,"");
    for( i=0; i < sizeofbuffer; i++)
    {
         printf("%*s    %d %d\n",indent,"",i,buffer[i]);
    }

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlScroobyLanguageChunk::PrintFormatted(int indent)
{
    unsigned int i;
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  pstring \"%s\" # Name        \n",indent,"",name);
    printf("%*s  byte  %12d # Language    \n",indent,"",language);
    printf("%*s  int   %12ld # NumStrings  \n",indent,"",numstrings);
    printf("%*s  int   %12ld # Modulo      \n",indent,"",modulo);
    printf("%*s  int   %12ld # SizeOfBuffer\n",indent,"",sizeofbuffer);
    printf("%*s  repeat 1 int   # Hashes      \n",indent,"");
    for( i=0; i < numstrings; i++)
    {
         printf("%*s    %12ld\n",indent,"",hashes[i]);
    }
    printf("%*s  endrepeat\n",indent,"");
    printf("%*s  repeat 1 int   # Offsets     \n",indent,"");
    for( i=0; i < numstrings; i++)
    {
         printf("%*s    %12ld\n",indent,"",offsets[i]);
    }
    printf("%*s  endrepeat\n",indent,"");
    printf("%*s  repeat 1 byte  # Buffer      \n",indent,"");
    for( i=0; i < sizeofbuffer; i++)
    {
         printf("%*s    %12d\n",indent,"",buffer[i]);
    }
    printf("%*s  endrepeat\n",indent,"");
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

