int tlScroobyTextBibleResourceChunk16::sortPriority = -1;

tlScroobyTextBibleResourceChunk16::tlScroobyTextBibleResourceChunk16()
{
    Init();
}

tlScroobyTextBibleResourceChunk16::tlScroobyTextBibleResourceChunk16(const tlScroobyTextBibleResourceChunk16& ch)
{
    Init();
    *this = ch;
}

tlScroobyTextBibleResourceChunk16::~tlScroobyTextBibleResourceChunk16()
{

    if(name != NULL){
        strdelete(name);
    }
    if(filename != NULL){
        strdelete(filename);
    }
}

tlScroobyTextBibleResourceChunk16::tlScroobyTextBibleResourceChunk16(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Scrooby::OLDRESOURCETEXTBIBLE);
    ident = Pure3D::Scrooby::OLDRESOURCETEXTBIBLE;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    version = f->GetLong();
    f->GetPString(buf);
    filename = strnew(buf);
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Scrooby::OLDRESOURCETEXTBIBLE);
    }
}

void
tlScroobyTextBibleResourceChunk16::Init()
{
    ident = Pure3D::Scrooby::OLDRESOURCETEXTBIBLE;
    name = NULL;
    version = 0;
    filename = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Scrooby::OLDRESOURCETEXTBIBLE);
    }
}

long 
tlScroobyTextBibleResourceChunk16::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( name );
    s += sizeof( version );
    s += strlen( filename );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

